$base = "$env:USERPROFILE\Desktop\AssetManagement"
$enc  = [System.Text.Encoding]::UTF8

# Fix 1: Template selection logic (PropertyType-based, fixed precedence bug)
$cp = "$base\AssetManagement.Web\Controllers\ContractsController.cs"
$cc = [System.IO.File]::ReadAllText($cp, $enc)
$oldL = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
$newL = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if ($cc.Contains($oldL)) {
    $cc = $cc.Replace($oldL, $newL)
    [System.IO.File]::WriteAllText($cp, $cc, $enc)
    Write-Host "OK: Template selection logic fixed" -ForegroundColor Green
} else {
    Write-Host "WARN: Pattern 1 not found exactly - showing current isComm line:" -ForegroundColor Yellow
    ($cc -split "`n") | Select-String "isComm" | Select-Object -First 5
}

# Fix 2: FullDetails - each stage history as its own detailed card
$fp = "$base\AssetManagement.Web\Views\Asset\FullDetails.cshtml"
$fc = [System.IO.File]::ReadAllText($fp, $enc)
$oldH = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
$newH = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if ($fc.Contains($oldH)) {
    $fc = $fc.Replace($oldH, $newH)
    [System.IO.File]::WriteAllText($fp, $fc, $enc)
    Write-Host "OK: FullDetails stage history redesigned" -ForegroundColor Green
} else {
    Write-Host "WARN: Pattern 2 not found exactly" -ForegroundColor Red
}

cd $base
dotnet build 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Build OK!" -ForegroundColor Green }